def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                base = np.sin(ratio * a * np.pi) + np.cos(a * ratio * 2)
                factor = (a ** 3.1) * np.exp(-ratio * a**0.8)
                if a % 4 == 1:
                    factor *= 1.07
                elif a % 5 == 0:
                    factor *= 0.85
                score += base * factor
            if int(capacity * item) % 7 == 3:
                score *= 0.91
            if score > 10:
                score /= 3.2
        elif 0.05 <= ratio < 0.2:
            prod = 1
            sum_log = 0
            for n in range(1, int(capacity)+3):
                val = (ratio + n / (n + 2)) * np.log1p(n + ratio)
                prod *= val if val != 0 else 1
                if prod > 1e7:
                    prod = np.log1p(prod) + sum_log
                    break
                sum_log += np.log1p(val)
            mod_val = int(abs(prod)) % 400
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 8 == 1) and ((item * 5) % 4 == 1):
                score += 6.7
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**3) % 1) * (x ** 2.2) * np.sin(x)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                part = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                if m % 2 == 0:
                    part *= 1.15
                else:
                    part *= 0.95
                score += part
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.45
            else:
                score -= remainder * 0.8
            if score < -4:
                score = abs(score) * 0.28 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 17:
                score /= 3.3
        elif 0.5 < ratio <= 0.9:
            penalty_base = 0
            for p in range(1, 12):
                term = ((ratio - 0.5) ** p) * (p ** 1.8)
                if term > 200:
                    term = np.sqrt(term)
                penalty_base += term
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) + 3
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 6) % 5 == 1) and (int(item * 9) % 13 == 3):
                score -= 5.5
            if score < 0:
                score *= -1.3
                score += 6
            if score > 110:
                score = 110
        elif 0.9 < ratio <= 1.4:
            penalty_ext = 0
            diff = ratio - 0.9
            for q in range(1, 13):
                val = ((diff) ** q) * (q ** 2.7) / (q + 0.7)
                penalty_ext += val
                if penalty_ext > 1300:
                    penalty_ext = np.log1p(penalty_ext) + 20
                    break
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 6 == 2) and (int(item * 10) % 5 == 1):
                score -= 8
            for z in range(1, 7):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1400:
                score = 1400
        else:
            mega_penalty = 0
            diff = ratio - 1.4
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.2)
                if term > 15000:
                    term = np.log1p(term)
                mega_penalty += term
            score = mega_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 3 == 1) and (int(item * 20) % 7 == 2):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.65 + 5
            if score > 2500:
                score = 2500
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
            if score < 1:
                score *= 1.7
        elif capacity < 7:
            score *= 2.7
        if abs(score) > 1600:
            score = np.sign(score) * 1600
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1.5
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        mean_val = np.mean(finite_priorities)
        fill_value = np.max(finite_priorities) * (10 + top_count) - median_val + mean_val * 0.5
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            if finite_priorities.size > 0:
                candidates = finite_priorities[(finite_priorities > quartiles[0]) & (finite_priorities < quartiles[2])]
                priorities[idx] = np.median(candidates) if candidates.size > 0 else np.median(finite_priorities)
            else:
                priorities[idx] = 0.5
    return priorities
